func  testAccCertificateDataSourceConfig_mostRecent(domain string, mostRecent bool) string {return fmt.Sprintf(`data "aws_acm_certificate" "test" {  domain1]q  most_recent = %[2]t}`, domain, mostRecent)}  
func  testAccCertificateDataSourceConfig_mostRecentAndTypes(domain, certType string, mostRecent bool) string {return fmt.Sprintf(`data "aws_acm_certificate" "test" {  domain1]q  types  = []  most_recent = %[3]t}`, domain, certType, mostRecent)}  
